const parts = msg.topic.split('/');
const deviceId = parts[3];
const imageIdFromTopic = parts[5];

const meta = msg.payload;

if (!meta || typeof meta !== 'object') {
    node.warn('invalid meta payload');
    return null;
}

if (!meta.imageId || meta.imageId !== imageIdFromTopic) {
    node.warn('meta imageId mismatch');
    return null;
}

const metaKey = `meta_${deviceId}_${imageIdFromTopic}`;

flow.set(metaKey, meta);

setTimeout(() => {
    flow.set(metaKey, undefined);
}, 60000);

return null;

const parts = msg.topic.split('/');
const deviceId = parts[3];
const imageId = parts[5];
const buffer = msg.payload;

const metaKey = `meta_${deviceId}_${imageId}`;
const completedKey = `completed_${deviceId}_${imageId}`;

function buildError(reason) {
    return {
        topic: `educacode/v1/devices/${deviceId}/images/${imageId}/error`,
        payload: JSON.stringify({ imageId, status: 'error', reason })
    };
}

function validateMeta(meta) {
    if (!meta) return 'meta_not_found';
    if (meta.imageId !== imageId) return 'image_id_mismatch';
    if (meta.mimeType !== 'image/png') return 'invalid_mime_type';
    if (meta.transferMode !== 'single') return 'invalid_transfer_mode';
    if (meta.encoding !== 'binary') return 'invalid_encoding';
    if (!Number.isInteger(meta.size)) return 'invalid_size';
    if (meta.size <= 0) return 'invalid_size';
    if (meta.size > 128 * 1024) return 'image_too_large';
    if (typeof meta.sha256 !== 'string') return 'invalid_sha256';
    if (!/^[a-f0-9]{64}$/i.test(meta.sha256)) return 'invalid_sha256';
    return null;
}

function validateAndPrepare(meta) {
    if (flow.get(completedKey)) {
        return null;
    }

    if (!Buffer.isBuffer(buffer)) {
        const err = buildError('payload_not_buffer');
        msg.errorTopic = err.topic;
        msg.errorPayload = err.payload;
        return [null, msg];
    }

    const metaError = validateMeta(meta);
    if (metaError) {
        flow.set(metaKey, undefined);
        const err = buildError(metaError);
        msg.errorTopic = err.topic;
        msg.errorPayload = err.payload;
        return [null, msg];
    }

    if (buffer.length !== meta.size) {
        flow.set(metaKey, undefined);
        const err = buildError('size_mismatch');
        msg.errorTopic = err.topic;
        msg.errorPayload = err.payload;
        return [null, msg];
    }

    const crypto = require('crypto');
    const hash = crypto.createHash('sha256').update(buffer).digest('hex');

    if (hash !== meta.sha256) {
        flow.set(metaKey, undefined);
        const err = buildError('checksum_mismatch');
        msg.errorTopic = err.topic;
        msg.errorPayload = err.payload;
        return [null, msg];
    }

    flow.set(metaKey, undefined);
    flow.set(completedKey, true);

    setTimeout(() => {
        flow.set(completedKey, undefined);
    }, 5 * 60 * 1000);

    const storedPath = `/signatures/${imageId}.png`;

    msg.filename = storedPath;
    msg.payload = buffer;
    msg.ackTopic = `educacode/v1/devices/${deviceId}/images/${imageId}/ack`;
    msg.ackPayload = JSON.stringify({
        imageId,
        status: 'completed',
        sha256Verified: true,
        storedPath
    });

    return [msg, null];
}

let meta = flow.get(metaKey);

if (meta) {
    return validateAndPrepare(meta);
}

setTimeout(() => {
    const delayedMeta = flow.get(metaKey);

    if (!delayedMeta) {
        if (flow.get(completedKey)) {
            return;
        }
        const err = buildError('meta_not_found');
        node.send([null, { errorTopic: err.topic, errorPayload: err.payload }]);
        return;
    }

    node.send(validateAndPrepare(delayedMeta));
}, 2000);

return null;

const parts = msg.topic.split('/');
const deviceId = parts[3];
const imageId = parts[5];

msg.errorTopic = `educacode/v1/devices/${deviceId}/images/${imageId}/error`;
msg.errorPayload = JSON.stringify({
    imageId,
    status: 'error',
    reason: 'file_write_failed'
});

return msg;
